/* === BASE TOOLBAR === */
#__billiax-toolbar { position: fixed; top: 0; left: 0; right: 0; z-index: 2147483640; background: linear-gradient(135deg, #1a1b2e 0%, #16213e 100%); color: #e2e8f0; font: 13px/1.4 -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; padding: 4px 16px; display: flex; align-items: center; gap: 4px; box-shadow: 0 2px 8px rgba(0,0,0,0.3); border-bottom: 1px solid rgba(99,102,241,0.3); flex-wrap: nowrap; overflow-x: auto; scrollbar-width: none; }
#__billiax-toolbar::-webkit-scrollbar { display: none; }
#__billiax-toolbar a { color: #93c5fd; text-decoration: none; padding: 2px 6px; border-radius: 5px; transition: all 0.15s; font-size: 11px; white-space: nowrap; }
#__billiax-toolbar a:hover { background: rgba(99,102,241,0.25); color: #bfdbfe; }
#__billiax-toolbar .t-label { font-weight: 700; color: #818cf8; font-size: 9px; text-transform: uppercase; letter-spacing: 0.5px; padding: 0 3px; white-space: nowrap; }
#__billiax-toolbar .t-sep { width: 1px; height: 14px; background: rgba(255,255,255,0.12); margin: 0 2px; flex-shrink: 0; }
#__billiax-toolbar .badge { background: rgba(239,68,68,0.3); color: #fca5a5; font-size: 9px; padding: 0 4px; border-radius: 6px; margin-left: 2px; font-weight: 600; }
#__billiax-toolbar .badge-pr { background: rgba(34,197,94,0.3); color: #86efac; }
#__billiax-toolbar .t-create { background: rgba(34,197,94,0.15); color: #86efac; border: 1px solid rgba(34,197,94,0.25); font-weight: 600; }
#__billiax-toolbar .t-create:hover { background: rgba(34,197,94,0.3); }
body { padding-top: 28px !important; }
.AppHeader { top: 28px !important; }

/* === MODE TOGGLE BUTTONS === */
#__billiax-toolbar input[type="radio"] { display: none; }
#__billiax-toolbar label.mode-btn { color: #64748b; padding: 2px 8px; border-radius: 5px; font-size: 10px; cursor: pointer; border: 1px solid transparent; transition: all 0.15s; white-space: nowrap; user-select: none; }
#__billiax-toolbar label.mode-btn:hover { color: #93c5fd; background: rgba(99,102,241,0.15); }

/* Active mode highlight via :has */
body:has(#__mode-default:checked) label[for="__mode-default"],
body:has(#__mode-compact:checked) label[for="__mode-compact"],
body:has(#__mode-focus:checked) label[for="__mode-focus"],
body:has(#__mode-hacker:checked) label[for="__mode-hacker"],
body:has(#__mode-midnight:checked) label[for="__mode-midnight"] { color: #e0e7ff !important; background: rgba(99,102,241,0.35) !important; border-color: rgba(99,102,241,0.5) !important; font-weight: 600 !important; }

/* === COMPACT MODE === */
body:has(#__mode-compact:checked) .AppHeader { padding: 4px 16px !important; min-height: auto !important; }
body:has(#__mode-compact:checked) .Box-row { padding: 6px 16px !important; }
body:has(#__mode-compact:checked) h1 { font-size: 22px !important; }
body:has(#__mode-compact:checked) h2 { font-size: 18px !important; }
body:has(#__mode-compact:checked) .container-xl, body:has(#__mode-compact:checked) .container-lg { max-width: 100% !important; padding-left: 12px !important; padding-right: 12px !important; }
body:has(#__mode-compact:checked) [class*="Layout-main"] { max-width: 100% !important; }
body:has(#__mode-compact:checked) .TimelineItem { padding: 6px 0 !important; }

/* === FOCUS MODE === */
body:has(#__mode-focus:checked) [class*="Sidebar"],
body:has(#__mode-focus:checked) aside,
body:has(#__mode-focus:checked) footer,
body:has(#__mode-focus:checked) [role="contentinfo"],
body:has(#__mode-focus:checked) [class*="footer"],
body:has(#__mode-focus:checked) .feed-right-sidebar,
body:has(#__mode-focus:checked) [class*="Layout-sidebar"] { display: none !important; }
body:has(#__mode-focus:checked) [class*="Layout-main"] { max-width: 960px !important; margin: 0 auto !important; width: 100% !important; }
body:has(#__mode-focus:checked) main { max-width: 100% !important; }

/* === HACKER MODE === */
body:has(#__mode-hacker:checked) { background: #0a0a0a !important; color: #00ff41 !important; font-family: 'Courier New', 'Fira Code', monospace !important; }
body:has(#__mode-hacker:checked) * { border-color: #1a3a1a !important; }
body:has(#__mode-hacker:checked) a:not(#__billiax-toolbar a) { color: #00cc33 !important; }
body:has(#__mode-hacker:checked) a:not(#__billiax-toolbar a):hover { color: #00ff41 !important; text-shadow: 0 0 8px #00ff41 !important; }
body:has(#__mode-hacker:checked) .AppHeader, body:has(#__mode-hacker:checked) header:not(#__billiax-toolbar) { background: #0a0a0a !important; border-bottom: 1px solid #1a3a1a !important; }
body:has(#__mode-hacker:checked) h1, body:has(#__mode-hacker:checked) h2, body:has(#__mode-hacker:checked) h3, body:has(#__mode-hacker:checked) h4 { color: #00ff41 !important; text-shadow: 0 0 4px rgba(0,255,65,0.3) !important; }
body:has(#__mode-hacker:checked) img:not([class*="avatar"]):not(#__billiax-toolbar img) { filter: grayscale(1) brightness(0.7) sepia(1) hue-rotate(70deg) saturate(5) !important; }
body:has(#__mode-hacker:checked) [class*="Box"], body:has(#__mode-hacker:checked) main, body:has(#__mode-hacker:checked) [class*="card"] { background: #0d0d0d !important; }
body:has(#__mode-hacker:checked) button:not(#__billiax-toolbar button), body:has(#__mode-hacker:checked) .btn { background: #1a3a1a !important; color: #00ff41 !important; border-color: #2a5a2a !important; }
body:has(#__mode-hacker:checked) input, body:has(#__mode-hacker:checked) textarea, body:has(#__mode-hacker:checked) select { background: #0a0a0a !important; color: #00ff41 !important; border-color: #1a3a1a !important; font-family: monospace !important; }
body:has(#__mode-hacker:checked) ::selection { background: #00ff41 !important; color: #000 !important; }
body:has(#__mode-hacker:checked) .AppHeader svg, body:has(#__mode-hacker:checked) header svg { fill: #00ff41 !important; color: #00ff41 !important; }

/* === MIDNIGHT BLUE MODE === */
body:has(#__mode-midnight:checked) { background: #0f172a !important; color: #cbd5e1 !important; }
body:has(#__mode-midnight:checked) a:not(#__billiax-toolbar a) { color: #60a5fa !important; }
body:has(#__mode-midnight:checked) .AppHeader, body:has(#__mode-midnight:checked) header:not(#__billiax-toolbar) { background: #1e293b !important; border-bottom-color: #334155 !important; }
body:has(#__mode-midnight:checked) h1, body:has(#__mode-midnight:checked) h2, body:has(#__mode-midnight:checked) h3 { color: #f1f5f9 !important; }
body:has(#__mode-midnight:checked) [class*="Box"], body:has(#__mode-midnight:checked) main, body:has(#__mode-midnight:checked) [class*="card"] { background: #1e293b !important; border-color: #334155 !important; }
body:has(#__mode-midnight:checked) button:not(#__billiax-toolbar button), body:has(#__mode-midnight:checked) .btn { background: #334155 !important; color: #e2e8f0 !important; border-color: #475569 !important; }
body:has(#__mode-midnight:checked) input, body:has(#__mode-midnight:checked) textarea, body:has(#__mode-midnight:checked) select { background: #1e293b !important; color: #e2e8f0 !important; border-color: #475569 !important; }
body:has(#__mode-midnight:checked) footer, body:has(#__mode-midnight:checked) [role="contentinfo"] { background: #0f172a !important; color: #64748b !important; }
body:has(#__mode-midnight:checked) svg { fill: #94a3b8 !important; color: #94a3b8 !important; }
body:has(#__mode-midnight:checked) .AppHeader svg { fill: #e2e8f0 !important; color: #e2e8f0 !important; }

{{#showHelp}}
/* === HELP PANEL === */
#__billiax-help-panel { display: none; position: fixed; top: 50%; left: 50%; transform: translate(-50%, -50%); z-index: 2147483645; background: rgba(15, 23, 42, 0.97); color: #e2e8f0; border: 1px solid rgba(99,102,241,0.3); border-radius: 16px; padding: 24px 28px; width: 520px; max-width: 90vw; max-height: 80vh; overflow-y: auto; box-shadow: 0 25px 60px rgba(0,0,0,0.5); font: 13px/1.5 -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; }
#__billiax-help-panel:target { display: block; }
#__billiax-help-backdrop { display: none; position: fixed; inset: 0; z-index: 2147483644; background: rgba(0,0,0,0.5); }
#__billiax-help-panel:target ~ #__billiax-help-backdrop { display: block; }
#__billiax-help-panel h3 { color: #818cf8; font-size: 14px; margin: 14px 0 8px; text-transform: uppercase; letter-spacing: 0.5px; }
#__billiax-help-panel h3:first-child { margin-top: 0; }
#__billiax-help-panel .shortcut-row { display: flex; justify-content: space-between; padding: 4px 0; border-bottom: 1px solid rgba(255,255,255,0.05); }
#__billiax-help-panel .shortcut-row:last-child { border-bottom: none; }
#__billiax-help-panel kbd { background: rgba(255,255,255,0.1); border: 1px solid rgba(255,255,255,0.15); border-radius: 4px; padding: 1px 6px; font-family: monospace; font-size: 12px; min-width: 20px; text-align: center; }
#__billiax-help-panel .close-link { display: inline-block; margin-top: 16px; color: #818cf8; text-decoration: none; padding: 6px 16px; border: 1px solid rgba(99,102,241,0.3); border-radius: 8px; }
#__billiax-help-panel .close-link:hover { background: rgba(99,102,241,0.2); }
#__billiax-toolbar .help-btn { color: #818cf8; font-weight: 700; font-size: 13px; border: 1px solid rgba(99,102,241,0.3); padding: 1px 7px; border-radius: 50%; }
#__billiax-toolbar .help-btn:hover { background: rgba(99,102,241,0.3); color: #e0e7ff; }
{{/showHelp}}

{{#showQuickIssue}}
/* === QUICK ISSUE PANEL === */
#__billiax-quick-issue { display: none; position: fixed; top: 50%; left: 50%; transform: translate(-50%, -50%); z-index: 2147483645; background: rgba(15, 23, 42, 0.97); color: #e2e8f0; border: 1px solid rgba(99,102,241,0.3); border-radius: 16px; padding: 20px 24px; width: 480px; max-width: 90vw; box-shadow: 0 25px 60px rgba(0,0,0,0.5); font: 13px/1.5 -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; }
#__billiax-quick-issue:target { display: block; }
#__billiax-quick-issue h3 { color: #818cf8; font-size: 15px; margin: 0 0 14px; }
#__billiax-quick-issue .qi-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 8px; margin-bottom: 12px; }
#__billiax-quick-issue .qi-repo { display: flex; align-items: center; gap: 6px; padding: 8px 12px; border-radius: 8px; background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); color: #93c5fd; text-decoration: none; font-size: 12px; transition: all 0.15s; }
#__billiax-quick-issue .qi-repo:hover { background: rgba(99,102,241,0.15); border-color: rgba(99,102,241,0.3); }
#__billiax-quick-issue .qi-repo .dot { width: 8px; height: 8px; border-radius: 50%; flex-shrink: 0; }
#__billiax-quick-issue .qi-close { display: inline-block; margin-top: 10px; color: #818cf8; text-decoration: none; padding: 6px 16px; border: 1px solid rgba(99,102,241,0.3); border-radius: 8px; font-size: 12px; }
#__billiax-quick-issue .qi-close:hover { background: rgba(99,102,241,0.2); }
#__billiax-toolbar .qi-btn { background: rgba(245,158,11,0.15); color: #fcd34d; border: 1px solid rgba(245,158,11,0.25); font-weight: 600; font-size: 11px; }
#__billiax-toolbar .qi-btn:hover { background: rgba(245,158,11,0.3); }
{{/showQuickIssue}}
